func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField
	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !validFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Build placeholders for departments
	placeholders := make([]string, len(departments))
	args := make([]interface{}, len(departments))
	for i, dept := range departments {
		placeholders[i] = "?"
		args[i] = dept
	}

	// Build SQL - note: we use field names directly since they are validated
	var sql string
	var params []interface{}

	if groupByField == "department" {
		sql = `
			SELECT
				u.department as group_value,
				COUNT(DISTINCT u.id) as user_count,
				COUNT(a.id) as total_activities
			FROM user_profile u
			LEFT JOIN user_activity a ON u.id = a.user_id
			WHERE u.department IN (` + joinStrings(placeholders, ",") + `)
			GROUP BY u.department`
		params = args
	} else if groupByField == "role" {
		sql = `
			SELECT
				u.role as group_value,
				COUNT(DISTINCT u.id) as user_count,
				COUNT(a.id) as total_activities
			FROM user_profile u
			LEFT JOIN user_activity a ON u.id = a.user_id
			WHERE u.department IN (` + joinStrings(placeholders, ",") + `)
			GROUP BY u.role`
		params = args
	} else { // display_name
		sql = `
			SELECT
				u.display_name as group_value,
				COUNT(DISTINCT u.id) as user_count,
				COUNT(a.id) as total_activities
			FROM user_profile u
			LEFT JOIN user_activity a ON u.id = a.user_id
			WHERE u.department IN (` + joinStrings(placeholders, ",") + `)
			GROUP BY u.display_name`
		params = args
	}

	// Use a struct to properly map the 3 columns
	var results []DepartmentReportSummary
	_, err := o.Raw(sql, params...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	output := make([]map[string]interface{}, len(results))
	for i, row := range results {
		output[i] = map[string]interface{}{
			"group_value":     row.GroupValue,
			"user_count":      row.UserCount,
			"total_activities": row.TotalActivities,
		}
	}

	return output, nil
}

// GenerateDepartmentReportByRole creates a summary report grouped by role.
