func GenerateDepartmentReportByRole(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	return GenerateDepartmentReport(o, departments, groupByField)
}

// Helper function to join strings with a separator
func joinStrings(strs []string, sep string) string {
	if len(strs) == 0 {
		return ""
	}
	if len(strs) == 1 {
		return strs[0]
	}
	result := strs[0]
	for _, s := range strs[1:] {
		result += sep + s
	}
	return result
}

