func GenerateDepartmentReportByRole(o orm.Ormer, department string) ([]map[string]interface{}, error) {
	sql := `
		SELECT
			u.role as group_value,
			COUNT(DISTINCT u.id) as user_count,
			COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department = ?
		GROUP BY u.role`

	var results []map[string]interface{}
	err := o.Raw(sql, department).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

// Helper function to join strings with a separator
func joinStrings(strs []string, sep string) string {
	if len(strs) == 0 {
		return ""
	}
	result := strs[0]
	for _, s := range strs[1:] {
		result += sep + s
	}
	return result
}

