		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Build placeholders for departments
	placeholders := make([]string, len(departments))
	for i := range placeholders {
		placeholders[i] = "?"
	}

	// Build args slice
	args := make([]interface{}, len(departments))
	for i, dept := range departments {
		args[i] = dept
	}

	// Map field names to column names
	fieldToColumn := map[string]string{
		"department":   "department",
		"role":         "role",
		"display_name": "display_name",
	}
	columnName := fieldToColumn[groupByField]

	// Build SQL - filter by the groupByField column, not just department
	sql := fmt.Sprintf(`
		SELECT
			u.%s as group_value,
			COUNT(DISTINCT u.id) as user_count,
			COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.%s IN (%s)
		GROUP BY u.%s`, columnName, columnName, joinStrings(placeholders, ","), columnName)

