	sql := fmt.Sprintf(`
		SELECT
			u.%s as group_value,
			COUNT(DISTINCT u.id) as user_count,
			COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.%s IN (%s)
		GROUP BY u.%s`, columnName, columnName, joinStrings(placeholders, ","), columnName)

