func GenerateDepartmentReportByDepartment(o orm.Ormer, departments []string) ([]map[string]interface{}, error) {
	return GenerateDepartmentReport(o, departments, "department")
}

// GenerateDepartmentReportByDisplayName creates a report grouped by display name.
